sql:
SELECT abalone_id
FROM abalone
WHERE length < (SELECT AVG(length) FROM abalone);

SELECT * 
FROM abalone 
WHERE sex = 'F' AND viscera_weight > 0.0007;

SELECT abalone_id, rings, sex, length, diameter, height, whole_weight, shucked_weight, viscera_weight, shell_weight, data_source_id, collection_id
FROM abalone
WHERE length > 0.2 AND diameter > 0.2 AND height > 0.03 AND whole_weight > 0.02 AND shucked_weight > 0.01 AND viscera_weight > 0.01 AND shell_weight > 0.015;

SELECT researcher_name
FROM researchers
ORDER BY researcher_name ASC;

SELECT sex, rings, CUME_DIST() OVER (PARTITION BY sex ORDER BY rings) AS cumulative_distribution
FROM abalone
ORDER BY rings;

SELECT COUNT(a.abalone_id) 
FROM abalone a 
JOIN data_collections dc ON a.collection_id = dc.collection_id;

SELECT sex, COUNT(*) as sex_count 
FROM abalone 
GROUP BY sex;

SELECT measurement_id, abalone_id, height
FROM measurements
WHERE height < (SELECT AVG(height) FROM measurements);

external_knowledge:
Physical attributes of the abalones include dimensions like length, diameter, height, and various weights;
Measurement details refer to the recorded weight, the type of measurement, the date it was taken, and any additional notes for each abalone;
The researchers' details include their name, the institution they are affiliated with, their email, their specialization, and their years of experience;
The data sources provide information on the origin of the abalone data, including the type of source, its name, and contact information;
Collection methods describe how each abalone was collected, along with the date and location of collection.

sql:
SELECT ab.abalone_id, ab.length
FROM abalone ab
INNER JOIN data_sources ds ON ab.data_source_id = ds.source_id;
